            _owner != address(0) &&
            isAdmin[_owner] != true &&
            isOperator[_owner] != true &&
            isSyndicate[_owner] != true &&
            isValidator[_owner] != true &&
            isExtension[_owner] != false
        );
        settings.roles.extension.cur -= 1;
